import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Cập Nhật Fabric","description":"Bộ hướng dẫn từng bước để cập nhật Fabric.","frontmatter":{"title":"Cập Nhật Fabric","description":"Bộ hướng dẫn từng bước để cập nhật Fabric.","authors":["IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"1.21.8/translated/vi_vn/players/updating-fabric.md","filePath":"versions/1.21.8/translated/vi_vn/players/updating-fabric.md","lastUpdated":1760721669000}`);var c={name:`1.21.8/translated/vi_vn/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Cập Nhật Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Cập Nhật Fabric”">​</a></h1><p>Bài hướng dẫn này sẽ giúp bạn cập nhật Fabric cho trình Launcher Minecraft chính thức.</p><p>Đối với các trình launcher bên thứ ba, bạn nên tham khảo tài liệu của họ.</p><p>Việc cập nhật Fabric là một quá trình khá tương đồng so với việc cài đặt Fabric, vì vậy đa phần bài hướng dẫn này sẽ giống với bài <a href="./installing-fabric">Cài Đặt Fabric</a>.</p><h2 id="vi-sao-toi-phai-cap-nhat-fabric-loader" tabindex="-1">Vì sao tôi phải cập nhật Fabric Loader? <a class="header-anchor" href="#vi-sao-toi-phai-cap-nhat-fabric-loader" aria-label="Permalink to “Vì sao tôi phải cập nhật Fabric Loader?”">​</a></h2><p>Những bản mod mới có thể yêu cầu phiên bản mới hơn của Fabric Loader để hoạt động, vì vậy bạn nên liên tục cập nhật nó để có thể sử dụng nhiều bản mod mới nhất.</p><h2 id="_1-tai-xuong-trinh-cai-đat-fabric" tabindex="-1">1. Tải xuống Trình cài đặt Fabric <a class="header-anchor" href="#_1-tai-xuong-trinh-cai-đat-fabric" aria-label="Permalink to “1. Tải xuống Trình cài đặt Fabric”">​</a></h2><p>Bạn có thể tải trình cài đặt Fabric từ <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">trang chủ Fabric</a>.</p><p>Nếu bạn sử dụng Windows, hãy tải phiên bản có đuôi <code>.exe</code> (<code>Download For Windows</code>), bởi vì nó không yêu cầu Java phải được cài trước đó trên hệ thống của bạn. Nó sẽ sử dụng phiên bản Java đi cùng trình launcher chính thức.</p><p>Đối với macOS và Linux, bạn nên tải phiên bản có đuôi <code>.jar</code>. Đôi khi, cách này sẽ yêu cầu Java phải được cài đặt trước đó.</p><h2 id="_2-chay-trinh-cai-đat-fabric" tabindex="-1">2. Chạy Trình cài đặt Fabric <a class="header-anchor" href="#_2-chay-trinh-cai-đat-fabric" aria-label="Permalink to “2. Chạy Trình cài đặt Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Hãy đóng Minecraft và trình Launcher của Minecraft trước khi cài đặt.</p></div><details class="details custom-block"><summary>Thông tin cho người dùng MacOS</summary><p>Trên macOS, bạn có thể cần bấm chuột phải vào tập tin <code>.jar</code> trong thư mục tải xuống của mình và bấm <code>Open</code> để chạy nó.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Trình cài đặt Fabric với chữ &quot;Cài đặt&quot; được tô đậm" loading="lazy"></p><p>Khi được hỏi &quot;Bạn có muốn mở nó không?&quot;, bấm <code>Open</code> lần nữa.</p></details><p>Ngay khi bạn mở trình cài đặt, bạn sẽ thấy màn hình như thế này:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Trình cài đặt Fabric với chữ &quot;Cài đặt&quot; được tô đậm" loading="lazy"></p><p>Để cài đặt Fabric, hãy chọn phiên bản trò chơi bạn muốn từ danh sách thả xuống, và bấm <code>install</code>.</p><p><strong>Hãy đảm bảo đã chọn &#39;Create Profile&#39;.</strong></p><p>Để cập nhật Fabric, đảm bảo chọn đúng cả phiên bản trò chơi và phiên bản loader rồi sau đó bấm <code>Cài Đặt</code>.</p><p><strong>Hãy đảm bảo bỏ chọn <code>Tạo Hồ Sơ</code> khi chạy trình cài đặt, nếu không, nó sẽ tạo hồ sơ mới mà có thể chúng ta không cần.</strong></p><h2 id="_3-mo-phan-ho-so-o-trinh-launcher-minecraft" tabindex="-1">3. Mở phần Hồ Sơ ở trình Launcher Minecraft <a class="header-anchor" href="#_3-mo-phan-ho-so-o-trinh-launcher-minecraft" aria-label="Permalink to “3. Mở phần Hồ Sơ ở trình Launcher Minecraft”">​</a></h2><p>Khi trình cài đặt hoàn tất, bạn có thể mở trình Launcher Minecraft và đi đến tab <code>Cài Đặt</code>. Chọn hồ sơ Fabric của bạn và mở màn hình chỉnh sửa.</p><p>Thay thể phiên bản cũ với một phiên bản mới hơn của Fabric Loader mà bạn đã cài trước đó, và bấm <code>Lưu</code>.</p><p><img src="/assets/players/updating-fabric.png" alt="Cập nhật phiên bản Fabric Loader ở trình Launcher Minecraft" loading="lazy"></p><h2 id="_4-ban-đa-hoan-tat" tabindex="-1">4. Bạn đã hoàn tất! <a class="header-anchor" href="#_4-ban-đa-hoan-tat" aria-label="Permalink to “4. Bạn đã hoàn tất!”">​</a></h2><p>Sau khi bạn đã hoàn thành xong các bước, bạn có thể quay trở lại tab <code>Chơi</code>, chọn hồ sơ Fabric từ danh sách thả xuống ở góc trái bên dưới và bấm nút chơi!</p><p>Nếu bạn gặp bất cứ vấn đề nào khi đang làm theo bài hướng dẫn này, bạn có thể xin sự trợ giúp từ kênh <code>#player-support</code> trong <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord Fabric</a>.</p>`,26)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};